import { Component, OnInit, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ProjectService } from '../../../core/services/project.service';
import { Project } from '../../../shared/models/project.model';

@Component({
  selector: 'app-project-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './project-list.component.html',
  styleUrl: './project-list.component.scss'
})
export class ProjectListComponent implements OnInit {
  // --- Data ---
  allProjects = signal<Project[]>([]);
  availableTags = signal<string[]>([]);
  availableTech = signal<string[]>([]);

  // --- Filter state ---
  selectedTag = signal<string>('All');
  selectedTech = signal<Set<string>>(new Set());

  // --- Derived: filtered results ---
  filteredProjects = computed(() => {
    const tag = this.selectedTag();
    const tech = this.selectedTech();

    return this.allProjects().filter(project => {
      const tagMatch = tag === 'All' || project.tags.includes(tag);
      const techMatch = tech.size === 0 || [...tech].every(t => project.tech.includes(t));
      return tagMatch && techMatch;
    });
  });

  // --- Derived: active filter count for UI badge ---
  activeFilterCount = computed(() => {
    let count = 0;
    if (this.selectedTag() !== 'All') count++;
    count += this.selectedTech().size;
    return count;
  });

  constructor(private projectService: ProjectService) {}

  ngOnInit() {
    this.projectService.getProjects().subscribe(p => this.allProjects.set(p));
    this.projectService.getAllTags().subscribe(t => this.availableTags.set(t));
    this.projectService.getAllTechStacks().subscribe(t => this.availableTech.set(t));
  }

  selectTag(tag: string) {
    this.selectedTag.set(tag);
  }

  toggleTech(tech: string) {
    // Signals require a new Set reference to trigger change detection
    const current = new Set(this.selectedTech());
    current.has(tech) ? current.delete(tech) : current.add(tech);
    this.selectedTech.set(current);
  }

  isTechSelected(tech: string): boolean {
    return this.selectedTech().has(tech);
  }

  clearAllFilters() {
    this.selectedTag.set('All');
    this.selectedTech.set(new Set());
  }
}
<section class="projects-page">

  <!-- Page Header -->
  <header class="page-header">
    <h1>Projects</h1>
    <p>Click any project for the full case study.</p>
  </header>

  <!-- ── FILTERS ────────────────────────────────────── -->
  <aside class="filters">

    <!-- Category filter (single-select) -->
    <div class="filter-group">
      <h3 class="filter-label">Category</h3>
      <div class="filter-pills">
        <button
          *ngFor="let tag of availableTags()"
          (click)="selectTag(tag)"
          [class.active]="selectedTag() === tag"
          class="pill">
          {{ tag }}
        </button>
      </div>
    </div>

    <!-- Tech stack filter (multi-select) -->
    <div class="filter-group">
      <h3 class="filter-label">Tech Stack</h3>
      <div class="filter-pills">
        <button
          *ngFor="let tech of availableTech()"
          (click)="toggleTech(tech)"
          [class.active]="isTechSelected(tech)"
          class="pill pill--tech">
          {{ tech }}
        </button>
      </div>
    </div>

    <!-- Clear button — only shows when filters are active -->
    <button
      *ngIf="activeFilterCount() > 0"
      (click)="clearAllFilters()"
      class="clear-btn">
      Clear filters
      <span class="badge">{{ activeFilterCount() }}</span>
    </button>

  </aside>
  <!-- ── END FILTERS ────────────────────────────────── -->

  <!-- Results count -->
  <p class="results-count">
    Showing <strong>{{ filteredProjects().length }}</strong>
    of {{ allProjects().length }} projects
  </p>

  <!-- Project Grid -->
  <div class="project-grid">
    <a
      *ngFor="let project of filteredProjects()"
      [routerLink]="['/projects', project.id]"
      class="project-card">

      <img [src]="project.thumbnail" [alt]="project.title" />

      <div class="card-body">
        <h2>{{ project.title }}</h2>
        <p>{{ project.tagline }}</p>

        <!-- Category tags -->
        <div class="tags">
          <span *ngFor="let tag of project.tags" class="tag">{{ tag }}</span>
        </div>

        <!-- Tech chips — highlights selected ones -->
        <div class="tech-chips">
          <span
            *ngFor="let tech of project.tech"
            class="chip"
            [class.chip--highlighted]="isTechSelected(tech)">
            {{ tech }}
          </span>
        </div>
      </div>
    </a>
  </div>

  <!-- Empty state -->
  <div *ngIf="filteredProjects().length === 0" class="empty-state">
    <p>No projects match your current filters.</p>
    <button (click)="clearAllFilters()" class="btn btn-secondary">Clear filters</button>
  </div>

</section>
